import pytest
from solution import intersection


# ---------------------------------------------------------------------------
# Happy path tests
# ---------------------------------------------------------------------------

class TestHappyPath:
    def test_basic_intersection(self):
        """Common elements returned in lst1 order."""
        assert intersection([1, 2, 3], [2, 3, 4]) == [2, 3]

    def test_order_follows_lst1(self):
        """Result order mirrors the order elements appear in lst1."""
        assert intersection([3, 1, 2], [1, 2, 3]) == [3, 1, 2]

    def test_strings(self):
        assert intersection(["a", "b", "c"], ["b", "c", "d"]) == ["b", "c"]

    def test_mixed_types(self):
        assert intersection([1, "a", 2, "b"], ["a", 2, "c"]) == ["a", 2]

    def test_full_overlap(self):
        """Every element in lst1 is also in lst2."""
        assert intersection([1, 2, 3], [3, 2, 1]) == [1, 2, 3]

    def test_single_common_element(self):
        assert intersection([1, 2, 3], [3, 4, 5]) == [3]

    def test_large_lists(self):
        lst1 = list(range(1000))
        lst2 = list(range(500, 1500))
        expected = list(range(500, 1000))
        assert intersection(lst1, lst2) == expected


