class TestDuplicates:
    def test_duplicates_in_lst1_deduplicated(self):
        """Duplicates in lst1 should appear only once in the result."""
        assert intersection([1, 1, 2, 2, 3], [1, 2, 3]) == [1, 2, 3]

    def test_duplicates_in_lst2_no_effect(self):
        """Duplicates in lst2 should not affect the result."""
        assert intersection([1, 2, 3], [1, 1, 2, 2]) == [1, 2]

    def test_duplicates_in_both_lists(self):
        assert intersection([1, 1, 2, 2], [1, 1, 2, 2]) == [1, 2]

    def test_all_duplicates_no_common(self):
        assert intersection([1, 1, 1], [2, 2, 2]) == []


